+  // ============================================================
+  // Cleanup
+  // ============================================================
+
+  /**
+   * Dispose of GPU resources.
+   */
+  dispose(): void {
+    this.pipelineCache.clear();
+    this.device?.destroy();
+    this.device = null;
+    this.adapter = null;
+    this.supported = false;
+  }
